277	  <!-- Markdown renderer + syntax highlighter, both from CDN -->
278	  <script src="https://cdn.jsdelivr.net/npm/marked/marked.min.js"></script>
279	  <script src="https://cdnjs.cloudflare.com/ajax/libs/highlight.js/11.9.0/highlight.min.js"></script>
280	  <script>
281	    const MD_FILE = 'variables_and_arithmetic_worksheet.md';
282	    const statusEl = document.getElementById('status');
283	    const contentEl = document.getElementById('content');
284	
285	    function showError(title, lines){
286	      statusEl.outerHTML =
287	        '<div class="errbox" role="alert"><h2>' + title + '</h2>' + lines.join('') + '</div>';
288	    }
289	
290	    async function render(){
291	      if (!window.marked){
292	        showError('Markdown renderer didn’t load',
293	          ['<p>The marked.js library couldn’t be reached from the CDN. Check your internet connection and reload.</p>']);
294	        return;
295	      }
296	      marked.setOptions({ gfm:true, breaks:false });
297	
298	      try{
299	        const res = await fetch(MD_FILE, { cache:'no-cache' });
300	        if(!res.ok) throw new Error('http-' + res.status);
301	        const md = await res.text();
302	
303	        contentEl.innerHTML = marked.parse(md);
304	
305	        // Highlight only blocks whose language is known; leave ASCII diagrams plain.
306	        contentEl.querySelectorAll('pre code').forEach(block => {
307	          const m = (block.className || '').match(/language-([\w-]+)/);
308	          const lang = m && m[1];
309	          if (lang && window.hljs && hljs.getLanguage(lang)){
310	            hljs.highlightElement(block);
311	          }
312	        });
313	
314	        document.title = (contentEl.querySelector('h1')?.textContent || document.title).trim();
315	        statusEl.remove();
316	        contentEl.hidden = false;
317	        document.body.classList.add('ready');
318	      }catch(err){
319	        const isFile = location.protocol === 'file:';
320	        if (isFile){
321	          showError('Open this over a local server, not as a file',
322	            ['<p>Browsers block a page opened with <code>file://</code> from reading other local files, so the worksheet can’t be fetched yet. Serve this folder over HTTP and reload:</p>',
323	             '<pre>cd path/to/this/folder\npython3 -m http.server 8000</pre>',
324	             '<p>Then open <code>http://localhost:8000/variables_and_arithmetic_worksheet.html</code></p>']);
325	        } else {
326	          showError('Worksheet file not found',
327	            ['<p>Couldn’t load <code>' + MD_FILE + '</code> next to this page. Keep both files in the same folder, then reload.</p>']);
328	        }
329	      }
330	    }
331	
332	    render();
333	  </script>
334	</body>
